import{_ as t,a,b as o,c as s}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as d,o as n,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Add an S3 Channel","description":"","frontmatter":{},"headers":[],"relativePath":"en/upload/s3.md","filePath":"en/upload/s3.md","lastUpdated":1781962217000}'),r={name:"en/upload/s3.md"};function c(h,e,p,u,f,m){return n(),i("div",null,[...e[0]||(e[0]=[l(`<h1 id="add-an-s3-channel" tabindex="-1">Add an S3 Channel <a class="header-anchor" href="#add-an-s3-channel" aria-label="Permalink to &quot;Add an S3 Channel&quot;">​</a></h1><h2 id="best-fit" tabindex="-1">Best Fit <a class="header-anchor" href="#best-fit" aria-label="Permalink to &quot;Best Fit&quot;">​</a></h2><p>Use the S3 channel when:</p><ul><li>You want to connect any S3-compatible object storage service, such as Cloudflare R2, Backblaze B2, MinIO, AWS S3, or another compatible provider.</li><li>You prefer the standard S3 configuration model: <code>Endpoint</code>, Access Key, and Secret Key.</li><li>You do not want to use the native Cloudflare R2 binding channel, or your storage provider is not Cloudflare R2.</li></ul><h2 id="what-you-need-before-you-start" tabindex="-1">What You Need Before You Start <a class="header-anchor" href="#what-you-need-before-you-start" aria-label="Permalink to &quot;What You Need Before You Start&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>The S3 API endpoint of the object storage service.</td></tr><tr><td>Bucket name</td><td>The bucket where files will be stored.</td></tr><tr><td>Region</td><td>Storage region. For Cloudflare R2, this is usually <code>auto</code>.</td></tr><tr><td>Access Key ID</td><td>S3 access key ID.</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key.</td></tr><tr><td>CDN domain</td><td>Optional custom domain for file access.</td></tr></tbody></table><p>Example for Cloudflare R2 through the S3 API:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://your-account-id.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: your-r2-bucket-name</span></span>
<span class="line"><span>Region: auto</span></span>
<span class="line"><span>Access Key ID: copied from the Cloudflare R2 API token</span></span>
<span class="line"><span>Secret Access Key: copied from the Cloudflare R2 API token</span></span></code></pre></div><h2 id="where-to-add-it" tabindex="-1">Where to Add It <a class="header-anchor" href="#where-to-add-it" aria-label="Permalink to &quot;Where to Add It&quot;">​</a></h2><ol><li>Open System Settings.</li><li>Go to Upload Settings.</li><li>Click Add Channel in the upper-right corner.</li><li>Select <code>S3</code>.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>What It Does</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>A friendly name for this S3 channel, such as <code>s3test</code> or <code>R2-S3</code>.</td><td>Yes</td></tr><tr><td>Enable channel</td><td>Controls whether this channel participates in upload selection.</td><td>Recommended</td></tr><tr><td>Endpoint</td><td>Full S3 service endpoint, including <code>https://</code>.</td><td>Yes</td></tr><tr><td>Custom CDN domain</td><td>Optional. When set, generated file links prefer this domain.</td><td>No</td></tr><tr><td>Bucket name</td><td>Bucket name, such as <code>s3test</code> or <code>img-r2</code>.</td><td>Yes</td></tr><tr><td>Bucket region</td><td>Region. For Cloudflare R2, this is usually <code>auto</code>.</td><td>Yes</td></tr><tr><td>Access Key ID</td><td>S3 access key ID.</td><td>Yes</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key.</td><td>Yes</td></tr><tr><td>Path-style access</td><td>Compatibility switch. Off by default. Some MinIO, OpenList, or self-hosted S3 services may require it.</td><td>No</td></tr><tr><td>Quota limit</td><td>Controls whether this S3 channel participates in upload selection based on capacity.</td><td>No</td></tr><tr><td>Capacity limit</td><td>Required after quota limit is enabled, for example <code>10 GB</code>.</td><td>Required when quota limit is enabled</td></tr><tr><td>Threshold</td><td>Stops writing after usage reaches this percentage, for example <code>90%</code>.</td><td>Required when quota limit is enabled</td></tr><tr><td>Remark</td><td>Notes for your own maintenance.</td><td>No</td></tr></tbody></table><h2 id="create-cloudflare-r2-s3-api-keys" tabindex="-1">Create Cloudflare R2 S3 API Keys <a class="header-anchor" href="#create-cloudflare-r2-s3-api-keys" aria-label="Permalink to &quot;Create Cloudflare R2 S3 API Keys&quot;">​</a></h2><ol><li>Open the Cloudflare Dashboard.</li><li>Go to <code>R2 Object Storage</code>.</li><li>Find <code>Manage R2 API Tokens</code> or the API token management entry.</li></ol><p>![R2 API token entry](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>Create an R2 API token that can access the target bucket.</li></ol><p><img src="`+t+'" alt="Create an account API token" loading="lazy"></p><ol start="5"><li>Copy the generated <code>Access Key ID</code> and <code>Secret Access Key</code>.</li></ol><p><img src="'+a+'" alt="Copy the token values" loading="lazy"></p><ol start="6"><li>Return to the R2 bucket page and confirm the bucket name.</li><li>Record the S3 API endpoint for the account. It usually looks like:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-account-id.r2.cloudflarestorage.com</span></span></code></pre></div><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Open Upload Settings.</li><li>Click Add Channel.</li><li>Select <code>S3</code>.</li><li>Enter a channel name you can recognize, for example <code>s3test</code>.</li><li>Enter the S3 API endpoint in <code>Endpoint</code>.</li><li>If you use a custom CDN, enter it in <code>Custom CDN domain</code>; otherwise leave it empty.</li><li>Enter the bucket name.</li><li>Enter the region. For the Cloudflare R2 example, use <code>auto</code>.</li><li>Enter the Access Key ID and Secret Access Key.</li><li>Leave path-style access off unless your provider explicitly requires it.</li><li>If you want capacity control, enable quota limit and enter the capacity limit and threshold.</li><li>Click Save.</li></ol><p><img src="'+o+'" alt="Add S3 configuration" loading="lazy"></p><h2 id="how-to-verify-it" tabindex="-1">How to Verify It <a class="header-anchor" href="#how-to-verify-it" aria-label="Permalink to &quot;How to Verify It&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>How to Verify</th></tr></thead><tbody><tr><td>Channel card appears</td><td>After saving, the Upload Settings page should show an S3 channel card.</td></tr><tr><td>Channel is enabled</td><td>The switch in the upper-right corner of the card should stay on.</td></tr><tr><td>Key fields are saved</td><td>The detail view should show Endpoint, Bucket, Region, path-style access, and related fields.</td></tr><tr><td>Upload works</td><td>Upload a test image and confirm that the object appears in the target bucket.</td></tr><tr><td>Link opens</td><td>The image link returned after upload should open normally.</td></tr><tr><td>Capacity display works</td><td>If quota limit is enabled, the card should show used capacity and the configured limit.</td></tr></tbody></table><p>S3 capacity statistics are calculated from ImgBed&#39;s local file records, not by querying the provider bucket in real time. After saving an S3 configuration, the system recalculates the quota ledger from the current D1 records.</p><p><img src="'+s+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="should-i-enable-path-style-access" tabindex="-1">Should I enable path-style access? <a class="header-anchor" href="#should-i-enable-path-style-access" aria-label="Permalink to &quot;Should I enable path-style access?&quot;">​</a></h3><p>Usually, no.</p><p>Enable it only when your S3-compatible provider does not support virtual-hosted-style URLs, or when the provider documentation explicitly requires path-style access. Some MinIO, self-hosted S3, and OpenList-compatible endpoints may need it.</p><h3 id="what-is-the-cdn-domain-for" tabindex="-1">What is the CDN domain for? <a class="header-anchor" href="#what-is-the-cdn-domain-for" aria-label="Permalink to &quot;What is the CDN domain for?&quot;">​</a></h3><p>If you put a CDN or custom access domain in front of the bucket, enter it here.</p><p>After it is configured, generated file links will prefer this domain. If you do not use a CDN, leave it empty.</p><h3 id="why-does-upload-fail" tabindex="-1">Why does upload fail? <a class="header-anchor" href="#why-does-upload-fail" aria-label="Permalink to &quot;Why does upload fail?&quot;">​</a></h3><p>Check these items first:</p><ol><li>The Endpoint includes the full <code>https://</code> URL.</li><li>The bucket name is correct.</li><li>The Region matches the provider requirement.</li><li>The Access Key ID and Secret Access Key were copied completely.</li><li>The key has write permission for the target bucket.</li><li>The provider does not require path-style access, or path-style access has been enabled if required.</li></ol><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Prepare S3 Endpoint, Bucket, Region, Access Key, and Secret Key</span></span>
<span class="line"><span>-&gt; Open Upload Settings</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; Select S3</span></span>
<span class="line"><span>-&gt; Enter Endpoint / Bucket / Region / Access Key / Secret Key</span></span>
<span class="line"><span>-&gt; Enter a CDN domain if needed</span></span>
<span class="line"><span>-&gt; Leave path-style access off by default</span></span>
<span class="line"><span>-&gt; Enable quota limit if needed</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; Upload a test image and check the result</span></span></code></pre></div>`,40)])])}const k=d(r,[["render",c]]);export{g as __pageData,k as default};
